'use strict';

const S = require('./item_content.cjs').sources;
const section = (heading, content, keyTerms) => ({ heading, content, keyTerms });
const chapter = (id, skillId, title, summary, objectives, sections, flashcards) => ({ id, skillId, title, summary, objectives, sections, flashcards });
const aid = (title, content, tags, domain, references = [S.ETS]) => ({ title, content, tags, domain, references });
const workshop = (id, title, taskType, prompt, stimulus, taskParts, planningFrame, successCriteria, commonPitfalls, sampleOutline, references) => ({ id, title, taskType, prompt, stimulus, taskParts, planningFrame, successCriteria, commonPitfalls, sampleOutline, references });

const chapters = [
  chapter('read5302-ch-01', 'literacy-foundations-development-profiles', 'Literacy Foundations, Development, and Learner Profiles',
    'Connect oral language, word recognition, comprehension, writing, development, culture, instruction, and diverse literacy profiles without reducing learners to labels.',
    ['Explain major interacting components of literacy.', 'Use developmental continua without rigid stage assumptions.', 'Differentiate instructional hypotheses across learner profiles.'], [
      section('Interacting models of literacy development', 'Literacy development involves oral language, phonological processing, print knowledge, word recognition, fluency, vocabulary, knowledge, comprehension, transcription, and composition. Models such as the Simple View and reading-rope representations organize important interactions but do not prescribe one assessment or lesson. Use a model to ask component questions, then test those questions with individual, linguistic, instructional, and functional evidence rather than treating a diagram as a diagnosis.', ['word recognition', 'language comprehension', 'literacy model']),
      section('Oral language, knowledge, and written language', 'Vocabulary, syntax, morphology, narrative, discourse, listening comprehension, and background knowledge support reading comprehension and written expression across grades. Print also expands language and knowledge. Compare oral and written tasks to identify whether print access, language comprehension, knowledge, or several demands constrain performance. Strong conversation does not guarantee academic language, and weak English performance does not establish weak language learning capacity.', ['oral language', 'academic language', 'background knowledge']),
      section('Development, variability, and literacy profiles', 'A developmental continuum describes related progressions in print concepts, sound awareness, decoding, spelling, fluency, comprehension, and writing, but skills overlap and learners vary. Composite scores can hide distinct profiles. Persistent inaccurate or effortful word recognition, decoding, and spelling can be consistent with dyslexia, but reversals and a single timed score are not diagnostic. Integrate instruction, opportunity, language, development, function, and current multidisciplinary criteria.', ['developmental continuum', 'dyslexia', 'component profile']),
      section('Curriculum coherence and responsive foundations', 'A coherent literacy system aligns standards, evidence-based progressions, rich texts, explicit foundational instruction, knowledge building, writing, assessment, intervention, and professional learning. Coherence is not rigid uniformity: educators adapt examples, scaffolds, intensity, language supports, access tools, and grouping while preserving important goals. Audit whose languages, identities, histories, and knowledge appear in materials and whether all students receive both strong core instruction and timely support.', ['curriculum coherence', 'evidence based', 'equity']),
    ], [['What are the two broad contributors in the Simple View?', 'Word recognition and language comprehension interact to support reading comprehension.'], ['Why assess oral language?', 'It clarifies vocabulary, syntax, discourse, listening, and knowledge contributions to reading and writing.'], ['Does a continuum require identical timing?', 'No. It organizes related development while individual skills and contexts vary.'], ['What word-level pattern can be associated with dyslexia?', 'Persistent difficulty with accurate or fluent recognition, decoding, and spelling under comprehensive evaluation.'], ['Why disaggregate a composite score?', 'The same total can result from different word-recognition, language, fluency, knowledge, or task profiles.'], ['What makes a curriculum coherent?', 'Aligned goals, progressions, instruction, texts, writing, assessment, intervention, and professional learning.']]),

  chapter('read5302-ch-02', 'phonological-awareness-print-alphabetic', 'Phonological Awareness, Print Concepts, and the Alphabetic Principle',
    'Build spoken-sound awareness and print knowledge into a clear bridge between phonemes, graphemes, decoding, and spelling.',
    ['Distinguish phonological, phonemic, and phonics constructs.', 'Analyze blending, segmentation, and manipulation tasks.', 'Design explicit cumulative instruction linking sound and print.'], [
      section('The spoken-sound continuum', 'Phonological awareness includes attention to words, syllables, onset-rime, and phonemes; phonemic awareness is the individual-phoneme level. Blending combines units, segmentation separates them, and deletion, addition, or substitution manipulates them. Tasks differ in linguistic and memory demands, so identify exactly what the learner must hear and do. A phoneme is a sound unit, not necessarily one printed letter, and sound-awareness tasks can be completed without print.', ['phonological awareness', 'phonemic awareness', 'phoneme']),
      section('Print concepts and alphabetic understanding', 'Concepts of print include book orientation, directionality, word boundaries, and distinctions among letters, words, and sentences. The alphabetic principle is the understanding that graphemes represent phonemes in systematic, though sometimes complex, ways. Letter-name knowledge can support learning but is not the same as knowing a letter’s sound functions. Connect print concepts to authentic reading and writing rather than assessing them only as decontextualized labels.', ['concepts of print', 'alphabetic principle', 'grapheme']),
      section('Blending, segmentation, and manipulation', 'Select a sound task that matches the instructional decision. A learner who blends but cannot segment needs different practice from a learner who cannot isolate initial sounds. Model with continuous pronunciation when appropriate, use counters or articulatory cues, provide many responses and immediate feedback, and vary word structure gradually. Watch for dialect and language differences so the target phoneme sequence reflects the learner’s speech rather than an assumed pronunciation.', ['blending', 'segmentation', 'manipulation']),
      section('Linking phonemes and graphemes', 'Once students can engage with the oral target, connect sounds with letters so awareness transfers to decoding and encoding. Instruction can move from common transparent correspondences to increasingly complex patterns while cumulatively reviewing prior learning. Do not create an artificial rule that all oral phonemic work must end before letters appear. Monitor both reading and spelling application and intensify explicitness, practice, or linguistic support based on error evidence.', ['sound–symbol mapping', 'encoding', 'cumulative instruction']),
    ], [['What is broader: phonological or phonemic awareness?', 'Phonological awareness; phonemic awareness is its individual-phoneme level.'], ['What is phoneme segmentation?', 'Separating a spoken word into its ordered individual phonemes.'], ['What is phoneme manipulation?', 'Deleting, adding, or substituting sounds within a spoken word.'], ['What is the alphabetic principle?', 'Understanding that letters and letter patterns systematically represent speech sounds.'], ['Are phonemes and letters identical?', 'No. Phonemes are sounds, and one phoneme may use one or multiple letters.'], ['Why pair phonemic work with letters?', 'The connection supports transfer to decoding, word recognition, and spelling.']]),

  chapter('read5302-ch-03', 'phonics-word-recognition-spelling-morphology', 'Phonics, Word Recognition, Spelling, and Morphology',
    'Teach and diagnose the phonological, orthographic, syllabic, and morphological knowledge that supports accurate and automatic word reading and spelling.',
    ['Design explicit phonics and encoding sequences.', 'Use orthographic and morphological analysis for complex words.', 'Translate error patterns into focused instruction.'], [
      section('Explicit phonics and connected application', 'Introduce a correspondence or pattern with a clear explanation and model, guide blending and spelling, mix cumulative review, and apply the target in words, phrases, sentences, and aligned connected text. Decodable text creates opportunity to use taught patterns, but it does not replace rich read-alouds, knowledge building, diverse literature, vocabulary, or composition. Correct errors by returning attention to the graphemes and sounds, then confirm pronunciation and meaning in context.', ['systematic phonics', 'decodable text', 'corrective feedback']),
      section('Orthographic mapping and high-frequency words', 'Orthographic mapping is the formation of durable links among a word’s phonemes, graphemes, and meaning after accurate analysis and successful retrieval. It is not memorizing a visual outline. For high-frequency words, identify regular correspondences and mark the unexpected part rather than declaring the whole word arbitrary. Sufficient phonemic skill, spelling-pattern knowledge, and repeated meaningful encounters support increasingly automatic recognition.', ['orthographic mapping', 'high-frequency word', 'automaticity']),
      section('Syllables, morphology, and multisyllabic words', 'Older and developing readers benefit from flexible analysis of vowel patterns, syllables, affixes, bases, and roots. Morphology supports pronunciation, spelling, vocabulary, and meaning across related words. Teach a manageable routine: locate meaningful parts, identify vowel and consonant patterns, try a pronunciation, adjust stress or schwa when needed, and confirm meaning in context. Avoid rigid division rules that fail across the complexity of English words.', ['syllable', 'morpheme', 'multisyllabic decoding']),
      section('Encoding and feature-based error analysis', 'Spelling requires learners to segment sounds, select graphemes, apply positional and syllable conventions, and represent morphology. Analyze which features are present or absent instead of counting only correct words. Parallel reading and spelling errors can reveal a target such as consonant clusters, vowel teams, inflectional endings, or morpheme boundaries. Use generative dictation and writing to test transfer, not copying alone, and document the response to explicit feedback.', ['encoding', 'spelling feature', 'error analysis']),
    ], [['What belongs in explicit phonics instruction?', 'Modeling, guided blending and encoding, cumulative review, feedback, and connected application.'], ['Why use decodable text?', 'It provides concentrated opportunity to apply correspondences that have been taught.'], ['What is orthographic mapping?', 'Bonding phonemes, graphemes, and meaning for rapid later retrieval.'], ['How should irregular words be taught?', 'Map their regular parts explicitly and identify the unexpected element.'], ['Why teach morphology?', 'It supports decoding, spelling, vocabulary, and meaning across related words.'], ['What makes spelling analysis useful?', 'It identifies represented and missing phonological, orthographic, syllabic, and morphological features.']]),

  chapter('read5302-ch-04', 'fluency-vocabulary-comprehension-knowledge', 'Fluency, Vocabulary, Comprehension, and Knowledge Building',
    'Develop accurate expressive reading, robust word knowledge, strategic comprehension, coherent knowledge, and evidence-centered discussion.',
    ['Interpret fluency beyond speed.', 'Plan robust vocabulary and morphology instruction.', 'Teach comprehension through strategy, structure, knowledge, and discussion.'], [
      section('Fluency as accuracy, automaticity, and prosody', 'Fluency integrates accurate word reading, an appropriate rate, and phrasing and expression that reflect syntax and meaning. Words correct per minute is useful for some decisions but is not the entire construct. Model fluent reading, use assisted or repeated oral reading with suitable texts, provide specific feedback, and check comprehension. A high rate with errors, poor phrasing, or weak understanding does not demonstrate fluent meaningful reading.', ['accuracy', 'automaticity', 'prosody']),
      section('Robust vocabulary and word learning', 'Select high-utility and domain-important words for explicit instruction while teaching students how to learn from morphology, context, reference tools, discussion, and wide reading. Provide student-friendly meanings, examples and nonexamples, semantic relationships, multiple contexts, active retrieval, speaking and writing, and cumulative review. Context produces hypotheses, not guaranteed definitions; readers verify meaning across the sentence, passage, word parts, and reliable sources.', ['vocabulary', 'semantic relationship', 'context clue']),
      section('Comprehension strategies and text structure', 'Explain why and when a strategy such as questioning, monitoring, summarizing, or inferring is useful; model the decision in a meaningful text; guide practice; and fade prompts. Teach narrative and informational structures, signal language, relationships, and how structure shapes summaries. A mnemonic can cue a process but is not the outcome. Comprehension instruction must remain connected to language, knowledge, accurate text access, evidence, and authentic purposes.', ['metacognition', 'text structure', 'summarizing']),
      section('Knowledge building, evidence, and discussion', 'Readers interpret new information through language and prior knowledge. Use coherent text sets, read-alouds, disciplinary sources, multimedia, and writing to build connected knowledge rather than isolated facts. Ask open text-dependent questions that require students to locate evidence, explain relationships, compare interpretations, and respond to peers. Design participation and language supports so evidence-centered discussion expands access instead of rewarding only the quickest speakers.', ['knowledge building', 'text evidence', 'discussion']),
    ], [['What are three dimensions of fluency?', 'Accuracy, appropriate rate or automaticity, and prosody.'], ['What supports fluency growth?', 'Modeled and repeated oral reading with suitable text, feedback, phrasing, and comprehension checks.'], ['What makes vocabulary instruction robust?', 'Clear meanings, morphology, semantic links, varied contexts, active use, and review.'], ['Is context always sufficient for word meaning?', 'No. It offers a hypothesis that may need morphology, passage evidence, or reference verification.'], ['How should a comprehension strategy be taught?', 'Explain, model, guide authentic practice, monitor meaning, and gradually release responsibility.'], ['Why build knowledge through connected texts?', 'Coherent knowledge supports vocabulary, inference, integration, and later comprehension.']]),

  chapter('read5302-ch-05', 'writing-disciplinary-digital-literacy', 'Writing, Disciplinary Literacy, and Digital Texts',
    'Link reading and writing while addressing transcription, composition, disciplinary reasoning, source use, and critical digital literacy.',
    ['Separate transcription from composition needs.', 'Teach discipline-specific reading and writing decisions.', 'Support source evaluation and multimodal synthesis.'], [
      section('Reading–writing reciprocity', 'Reading exposes students to knowledge, vocabulary, syntax, genre, evidence, and author decisions; writing requires close analysis and generative use of those resources. Integrate annotation, discussion, note making, sentence work, source synthesis, and composition while still teaching distinct reading and writing needs directly. Writing does not automatically remediate decoding, and reading volume does not automatically build strategic composition. Define the purpose and intended transfer.', ['reading–writing connection', 'transfer', 'mentor text']),
      section('Transcription, language, and composition', 'Writing can be constrained by handwriting or keyboarding, spelling, sentence construction, vocabulary, planning, organization, evidence, revision, or self-regulation. Assess these components under known conditions and with relevant access supports. Teach procedures explicitly, use models and guided practice, and create authentic audiences and purposes. A short product may reflect effortful transcription rather than weak ideas, so compare oral explanation, supported composition, and independent writing carefully.', ['transcription', 'composition', 'revision']),
      section('Disciplinary and source-based literacy', 'Disciplines differ in the questions they ask, evidence they value, texts and representations they use, and conventions for claims. Help content teachers apprentice students into these practices: reading graphs with prose, sourcing historical documents, explaining scientific mechanisms, or justifying mathematical reasoning. Source-based writing requires selecting relevant evidence, representing it accurately, attributing it, explaining the claim–evidence link, and considering counterevidence and audience.', ['disciplinary literacy', 'source evaluation', 'claim–evidence reasoning']),
      section('Digital, media, and multimodal literacy', 'Digital reading adds navigation, hyperlinks, multimodal integration, search, authorship, algorithms, distraction, privacy, and credibility decisions. Teach students to define a purpose, inspect the source, verify claims laterally, trace evidence, compare representations, and synthesize across modes. Familiarity with devices does not equal critical literacy. Accessibility features can expand participation, but teams must define whether a task measures content comprehension, navigation, source evaluation, or an unaided print skill.', ['digital literacy', 'lateral reading', 'multimodal text']),
    ], [['How can reading support writing?', 'It supplies knowledge, vocabulary, structures, evidence, and models for author decisions.'], ['Why separate transcription and composition?', 'Effortful spelling or handwriting can mask stronger language, planning, and ideas.'], ['What is disciplinary literacy?', 'The characteristic texts, evidence, representations, and reasoning practices of a discipline.'], ['What makes evidence useful in writing?', 'Relevance, accurate integration and attribution, and explanation of how it supports the claim.'], ['Does digital familiarity prove critical literacy?', 'No. Navigation, source evaluation, verification, synthesis, and attention require explicit teaching.'], ['What is lateral verification?', 'Leaving a source to investigate its authorship, evidence, reputation, and corroboration elsewhere.']]),

  chapter('read5302-ch-06', 'instructional-design-differentiation-engagement', 'Instructional Design, Differentiation, Intervention, and Engagement',
    'Design explicit, responsive, accessible literacy instruction that preserves rigor and builds engagement across core and intensive settings.',
    ['Use modeling, guided practice, feedback, and release.', 'Differentiate access and intensity from the intended construct.', 'Intensify intervention through documented data-based hypotheses.'], [
      section('Explicit instruction and gradual independence', 'State the target and purpose, activate needed knowledge, model the thinking or procedure, guide many successful responses, provide immediate specific feedback, and move toward independent and varied application. Cumulative review helps stabilize learning. Explicit does not mean passive or scripted forever; students should explain, compare, retrieve, and apply. Adjust prompt strength and pacing from response evidence rather than fading support on a calendar.', ['explicit instruction', 'guided practice', 'feedback']),
      section('Differentiation, grouping, and access', 'Group learners temporarily for a specific assessed need and regroup as evidence changes. Differentiate examples, scaffolds, materials, language supports, dosage, response mode, and feedback while preserving the meaningful goal. Access tools can support grade-level content at the same time that direct intervention addresses a foundational skill. Document which construct is being measured so assisted comprehension is not reported as unaided decoding or transcription.', ['flexible grouping', 'differentiation', 'accessibility']),
      section('Multilingual and culturally responsive design', 'Build on home-language literacy, vocabulary, family and cultural knowledge, and cross-linguistic patterns while explicitly teaching English sounds, spellings, morphology, syntax, discourse, and disciplinary language as needed. Use comprehensible interaction, models, visuals, structured talk, and opportunities for complex thinking. Do not confuse English development with disability or use language support as a reason to reduce intellectual demand.', ['multilingual learner', 'cross-linguistic transfer', 'language objective']),
      section('Intervention intensity, environment, and engagement', 'When progress is insufficient, first examine implementation and access, then use error and diagnostic evidence to adjust group size, time, frequency, explicitness, practice, feedback, target skill, or language support. Mark changes and monitor response. A literacy-rich environment offers diverse usable texts, student work, writing tools, and authentic purposes. Engagement grows through competence, relevance, identity, choice, belonging, and visible strategy-linked growth—not prizes or public speed comparisons alone.', ['intervention intensity', 'fidelity', 'engagement']),
    ], [['What makes instruction explicit?', 'A clear goal, modeled reasoning, supported practice, feedback, cumulative review, and responsive release.'], ['What makes grouping flexible?', 'Membership changes according to a specific skill, task, and current evidence.'], ['How can differentiation preserve rigor?', 'Change access, scaffolding, intensity, or response supports while maintaining the important goal.'], ['Can access and intervention occur together?', 'Yes. Provide content access while directly teaching and separately measuring the target skill.'], ['What precedes intensifying an intervention?', 'Review implementation, access, progress, and diagnostic or error evidence.'], ['What supports engagement?', 'Achievable challenge, relevance, identity, choice, belonging, authentic purpose, and successful strategy use.']]),

  chapter('read5302-ch-07', 'assessment-purposes-measurement-fairness', 'Assessment Purposes, Measurement, Selection, and Fairness',
    'Choose and interpret screening, diagnostic, progress, and outcome evidence according to construct, technical quality, access, and decision purpose.',
    ['Match assessment type to the question.', 'Apply reliability, validity, classification, and uncertainty concepts.', 'Evaluate fairness and accommodations without changing the construct silently.'], [
      section('Screening, diagnosis, monitoring, and outcomes', 'Screening efficiently identifies elevated risk and a follow-up pathway; it does not diagnose a disability or prescribe one program. Diagnostic assessment analyzes components and errors to guide hypotheses and instruction. Progress monitoring repeatedly measures change toward a goal, and outcome assessment examines performance after a period or program. One tool may serve more than one purpose only when evidence supports that use. State the decision before selecting the measure.', ['screening', 'diagnostic assessment', 'progress monitoring']),
      section('Reliability, validity, and uncertainty', 'Reliability concerns score consistency and measurement error; validity concerns evidence supporting a specific interpretation and use. A reliable score can support an invalid conclusion. Standard error and confidence intervals discourage false precision, especially near cut points or when changes are small. Examine construct coverage, administration, scoring, population, consequences, and converging data rather than treating reliability or validity as permanent yes-or-no labels.', ['reliability', 'validity', 'confidence interval']),
      section('Classification, norms, criteria, and fairness', 'Sensitivity and specificity describe how a screener classifies students with and without target risk; cutoffs also involve prevalence, consequences, resources, and equity. Norm-referenced results compare a learner with a defined group, while criterion-referenced evidence compares performance with specified skills. Fairness requires access to the intended construct and analysis of bias, subgroup evidence, opportunity, language, disability, and consequences—not identical treatment regardless of barriers.', ['sensitivity', 'specificity', 'fairness']),
      section('Selection, administration, and accommodations', 'Select an assessment because it fits the construct, learner, language, grade, purpose, norms, technical evidence, time, accessibility, and follow-up decision. Follow administration and scoring rules when using standard scores. An accommodation reduces an access barrier without altering the target construct; a modification may change what the score means. Document all departures and interpret supported and unsupported performance accurately. Use multiple sources for consequential decisions.', ['test selection', 'accommodation', 'standardization']),
    ], [['What does a screening result establish?', 'Risk and need for follow-up, not diagnosis or eligibility by itself.'], ['What does reliability address?', 'Score consistency, precision, and measurement error.'], ['What does validity address?', 'Evidence for an intended score interpretation and use.'], ['What do sensitivity and specificity address?', 'Correct identification and correct exclusion in classification.'], ['How do norm and criterion interpretations differ?', 'Norms compare with a group; criteria compare with defined skills or standards.'], ['What must an accommodation preserve?', 'The intended construct, with any effect on comparability documented.']]),

  chapter('read5302-ch-08', 'diagnostic-error-analysis-case-integration', 'Diagnostic Literacy Assessment, Error Analysis, and Case Integration',
    'Analyze component skills and authentic literacy performance, resolve conflicting data, and translate a defensible case formulation into instruction.',
    ['Use feature and error analysis across reading, spelling, and writing.', 'Integrate multilingual and disability evidence responsibly.', 'Communicate conclusions, uncertainty, and actionable next steps.'], [
      section('Word-level and phonological diagnostics', 'Compare phoneme blending, segmentation, manipulation, letter–sound knowledge, real- and unfamiliar-word reading, spelling, and connected-text errors. Novel-word tasks can show generative decoding but must use legal, appropriate patterns and be interpreted with language and instruction. Identify whether errors involve omissions, substitutions, clusters, vowels, positional patterns, syllables, or morphemes. Link the confirmed pattern to an explicit target and monitor transfer across decoding and encoding.', ['pseudoword', 'phoneme analysis', 'word-reading error']),
      section('Fluency, comprehension, and writing evidence', 'For oral reading, consider accuracy, rate, prosody, text difficulty, language, and understanding. Assess comprehension across vocabulary, syntax, knowledge, inference, structure, monitoring, summary, discussion, and source use with appropriate print access. Analyze writing for transcription, sentence construction, vocabulary, organization, genre, evidence, cohesion, and revision. A single passage level, retell, or holistic score is descriptive evidence—not a complete diagnosis.', ['oral reading fluency', 'comprehension', 'writing sample']),
      section('Multilingual and dyslexia differential evidence', 'Gather language history, opportunity, quality and duration of instruction, performance across languages and settings, family evidence, valid measures, and response to targeted teaching. Cross-linguistic features can inform explicit contrasts without being pathologized. A dyslexia evaluation examines persistent word reading, decoding, spelling, fluency, phonological and related evidence, function, instruction, strengths, and co-occurring factors under current criteria. No reversal checklist or single discrepancy score is sufficient.', ['language difference', 'dyslexia evaluation', 'instructional opportunity']),
      section('Case synthesis and instructional decisions', 'Organize the case around the referral decision: strengths, needs, component patterns, converging and conflicting evidence, technical and access limits, instruction and response, functional impact, and uncertainty. When sources disagree, compare constructs, task conditions, reliability, timing, fidelity, and language. Recommend prioritized feasible instruction, progress measures, family and student communication, needed referrals, and a review date. Do not convert an instructional report into unilateral eligibility or diagnosis.', ['case formulation', 'converging evidence', 'instructional recommendation']),
    ], [['What does pseudoword reading sample?', 'Generative application of legal sound–spelling and word-analysis knowledge.'], ['Why analyze spelling features?', 'They reveal represented and missing phonological, orthographic, syllabic, and morphological knowledge.'], ['Is words-correct-per-minute the whole fluency construct?', 'No. Accuracy, prosody, text, language, and comprehension also matter.'], ['What belongs in multilingual differential assessment?', 'Language, opportunity, instruction, cross-language performance, valid measures, and response to teaching.'], ['Can one timed word list diagnose dyslexia?', 'No. Diagnosis requires comprehensive converging evidence under current criteria.'], ['What makes a case synthesis actionable?', 'It links evidence and uncertainty to prioritized instruction, monitoring, communication, referrals, and review.']]),

  chapter('read5302-ch-09', 'progress-monitoring-data-mtss', 'Progress Monitoring, Instructional Decisions, and MTSS Data',
    'Build comparable progress series, interpret growth and fidelity, adapt intervention through data-based hypotheses, and communicate trends responsibly.',
    ['Establish defensible baselines, goals, and decision rules.', 'Interpret level, slope, variability, and implementation together.', 'Use individual and system data without deficit assumptions.'], [
      section('Comparable measurement and baseline', 'A progress series requires a technically adequate measure of the intended outcome, equivalent forms or a stable task, consistent administration and scoring, and documented conditions. Establish baseline with the publisher’s recommended procedure or multiple representative observations rather than one extreme score. Changing measure, grade, passage difficulty, timing, or scoring can create artificial trends. If a change is necessary, document the break and avoid pretending the series is continuous.', ['baseline', 'equivalent form', 'measurement comparability']),
      section('Goals, graphs, level, and slope', 'Define the measure, baseline, time-bound goal, expected direction, monitoring frequency, and decision rule before interpreting the data. Level describes current performance; slope describes rate of change; variability affects confidence. Examine the whole series and relevant aim line rather than one score. Goals should be ambitious, meaningful, and justified through norms, benchmarks, research, learner evidence, and team judgment—not selected after the results are known.', ['aim line', 'slope', 'decision rule']),
      section('Fidelity and data-based individualization', 'Before attributing weak growth to the learner, examine whether content, dosage, grouping, explicit procedures, materials, and access supports were delivered as planned. With adequate fidelity and insufficient response, use diagnostic and error data to form a hypothesis and adjust one or more intensity dimensions deliberately. Mark the phase change, continue frequent measurement, and decide whether the adaptation improves growth. Random program switching cannot reveal which change mattered.', ['implementation fidelity', 'phase change', 'data-based individualization']),
      section('Student, family, classroom, and system use', 'Explain graphs to students and families using the skill, goal, trend, uncertainty, instructional response, and next review rather than acronyms alone. Invite context and goal setting without public rank comparisons. At grade or school level, disaggregate outcomes and examine curriculum, opportunity, implementation, access, fairness, resources, and stakeholder experience before blaming a group or teacher. Document an action, owner, measure, and review date so meetings produce learning rather than dashboards only.', ['student goal setting', 'data communication', 'system inquiry']),
    ], [['What makes weekly scores comparable?', 'A stable outcome, equivalent forms, consistent administration and scoring, and documented conditions.'], ['Why use multiple baseline observations?', 'They reduce the influence of an atypical starting score.'], ['What does level describe?', 'Current performance in the measured series.'], ['What does slope describe?', 'The direction and rate of change over time.'], ['What precedes an intervention adaptation?', 'Review implementation, access, progress, and diagnostic evidence to form a reasoned hypothesis.'], ['Why mark a phase change?', 'It documents when an instructional adaptation began so the following trend can be evaluated.']]),

  chapter('read5302-ch-10', 'diverse-learners-family-equity-access', 'Diverse Learners, Family Partnership, Equity, and Access',
    'Use multilingual, cultural, family, disability, advanced-learning, and access evidence to design equitable literacy opportunities and decisions.',
    ['Apply asset-based cross-linguistic reasoning.', 'Build reciprocal family and community partnership.', 'Evaluate representation, accessibility, and advanced-learning needs.'], [
      section('Multilingual literacy and cross-linguistic transfer', 'Identify what learners know in each language, how their languages represent sounds and meanings, and how prior literacy can support English learning. Teach new English contrasts explicitly without prohibiting home-language use. Analyze whether errors are predictable transfer, developing English, limited opportunity, or persistent difficulty across contexts. Use qualified multilingual assessment and interpretation whenever possible; unvalidated translation does not preserve norms or constructs automatically.', ['multilingual literacy', 'cross-linguistic transfer', 'English development']),
      section('Reciprocal family and community partnership', 'Learn family goals, languages, literacy practices, texts, histories, schedules, access, and preferred communication methods. Share assessment and instruction in accessible nondeficit language and co-design realistic ways to support reading, writing, storytelling, discussion, and knowledge at home and in the community. Do not measure partnership only through event attendance or ask children to interpret confidential meetings. Families contribute expertise rather than merely receiving school directions.', ['family engagement', 'community literacy', 'language access']),
      section('Representation, culture, and critical access', 'Audit who authors texts, whose identities and histories appear, how groups are portrayed, which languages and formats are available, and who can enter advanced or intervention opportunities. Select accurate varied texts across the year rather than isolating diversity in celebrations. Maintain complexity with scaffolds and invite examination of perspective, evidence, omission, and power. Culturally responsive instruction combines representation and relevance with explicit skill, knowledge, and critical analysis.', ['representation', 'culturally responsive', 'critical literacy']),
      section('Disability, advanced learning, and assistive tools', 'Learners may have disabilities, advanced strengths, or both. Use evidence to provide intensive instruction, grade-level access, richer inquiry, acceleration or depth, and assistive technology as appropriate. Define the construct: speech-to-text can support composition while transcription is assessed separately; text-to-speech can support content access while decoding receives direct instruction. Avoid repetitive extra work for advanced readers and lowered expectations for students using accommodations.', ['assistive technology', 'twice exceptional', 'access tool']),
    ], [['What is asset-based multilingual instruction?', 'Build on language, literacy, culture, and knowledge resources while explicitly teaching new forms.'], ['Can an English-only score distinguish difference from disability?', 'No. Use language, opportunity, instruction, cross-language evidence, valid measures, and response to teaching.'], ['What makes family partnership reciprocal?', 'Shared goals and decisions that value family languages, knowledge, routines, access, and expertise.'], ['What should a representation audit ask?', 'Who is present, absent, authoring, portrayed, accessing complexity, and participating across the curriculum.'], ['How should advanced readers be supported?', 'Through depth, complexity, inquiry, authentic writing, choice, responsive pacing, and attention to uneven needs.'], ['How should assistive technology be interpreted?', 'According to the intended construct, access purpose, conditions, and separately measured target skills.']]),

  chapter('read5302-ch-11', 'coaching-professional-learning-collaboration', 'Coaching, Professional Learning, Collaboration, and Conflict Resolution',
    'Lead trustworthy coaching cycles and job-embedded adult learning that connect evidence, teacher agency, implementation, and student opportunity.',
    ['Clarify coaching roles and evidence use.', 'Design modeling, rehearsal, feedback, and follow-up.', 'Facilitate conflict and data inquiry toward testable actions.'], [
      section('Coaching agreements and cycles', 'Before observation, clarify whether the work is coaching or evaluation, its goal, roles, decision authority, confidentiality and policy limits, evidence to collect, and how feedback will be used. A cycle typically includes collaborative goal setting, co-planning, enactment, evidence collection, reflection, and a next step. Trust does not require avoiding student evidence; it requires transparency, respect, relevance, and reliable follow-through.', ['coaching agreement', 'confidentiality', 'coaching cycle']),
      section('Modeling, co-planning, co-teaching, and feedback', 'Choose a support mode that fits the teacher’s goal and context. Modeling is strongest when the focus and instructional decisions are visible and followed by debrief and rehearsal. Co-planning connects evidence with materials and anticipated responses; co-teaching shares enactment; observation and feedback use agreed look-fors and student evidence. Feedback should be specific, timely, dialogic, feasible, and linked to a next opportunity to practice.', ['modeling', 'co-teaching', 'feedback']),
      section('Adult learning and professional-learning evaluation', 'Adults bring expertise, identities, goals, constraints, and prior beliefs. Use relevant problems, voice and choice, active rehearsal, collaboration, feedback, resources, and immediate classroom application. Evaluate more than attendance or satisfaction: examine educator knowledge, practice, implementation conditions, student opportunities and outcomes, subgroup effects, and unintended consequences. Avoid claiming that one workshop or score caused every observed change.', ['adult learning', 'job embedded', 'professional learning evaluation']),
      section('Conflict resolution and disciplined data inquiry', 'When educators disagree, define the shared student goal, surface assumptions and evidence, distinguish interests from positions, and agree on a testable instructional plan with a review date. Productive data meetings begin with a focused question and prepared disaggregated evidence, consider instruction and access rather than deficit explanations, and end with a documented action, owner, measure, and follow-up. Psychological safety and accountability can coexist.', ['conflict resolution', 'data meeting', 'shared goal']),
    ], [['What should a coaching agreement clarify?', 'Role, purpose, confidentiality limits, goals, evidence, decision authority, and feedback use.'], ['What makes modeling transferable?', 'A shared focus, visible decision reasoning, look-fors, debriefing, rehearsal, and follow-up.'], ['What is job-embedded professional learning?', 'Learning tied to actual planning, teaching, student evidence, practice, feedback, and refinement.'], ['How should professional learning be evaluated?', 'Through educator learning and practice, conditions, student opportunity and outcomes, and unintended effects.'], ['What starts constructive conflict resolution?', 'A shared student goal plus transparent assumptions, evidence, interests, and decision process.'], ['What should a data meeting produce?', 'A documented testable action, owner, measure, and review date.']]),

  chapter('read5302-ch-12', 'program-leadership-mtss-ethics-privacy', 'Program Leadership, MTSS, Ethics, Privacy, and Advocacy',
    'Coordinate literacy systems, evaluate programs and materials, protect student data, disclose conflicts, and advocate through evidence and community partnership.',
    ['Lead coherent MTSS and program evaluation.', 'Appraise evidence and implementation fit before adoption.', 'Apply privacy, conflict-of-interest, and responsible advocacy principles.'], [
      section('MTSS and coherent literacy systems', 'A strong multi-tiered system begins with high-quality accessible core literacy instruction, universal screening with follow-up, timely targeted support, valid progress monitoring, collaborative decisions, and intensification based on response. Tiers describe support intensity, not fixed student identities. Specialists coordinate with classroom, special education, multilingual, psychology, speech-language, administration, and family partners. MTSS must not delay a required evaluation or make one person solely responsible for struggling readers.', ['MTSS', 'tiered support', 'collaboration']),
      section('Program, curriculum, and material evaluation', 'Before adoption, examine independent evidence quality and population, content scope and sequence, instructional design, assessment alignment, cultural and linguistic representation, accessibility, teacher knowledge and materials, scheduling, cost, and local fit. During implementation, measure opportunity, fidelity, educator learning, component and outcome growth, subgroup access, stakeholder experience, and unintended effects. A vendor citation list or one year-end average does not answer whether a program works for whom and why.', ['program evaluation', 'curriculum adoption', 'implementation']),
      section('Ethics, privacy, and professional boundaries', 'Share identifiable reading data only for an authorized educational purpose using current FERPA, state, local, and organizational rules, legitimate educational interest, secure methods, and the minimum necessary information. Clarify specialist, coach, evaluator, and diagnostic roles and work within competence. Disclose financial or personal conflicts, protect assessment materials and student dignity, and avoid guarantees, public rankings, or marketing uses of student data without authority.', ['FERPA', 'professional ethics', 'conflict of interest']),
      section('Evidence-based advocacy and continuous improvement', 'Advocacy combines student and family experience, disaggregated data, credible research, legal and equity analysis, resource and implementation implications, and transparent uncertainty. Center communities affected by the decision and present alternatives and tradeoffs rather than selecting only favorable evidence. Define a measurable change theory, supports, safeguards, and review process. Continuous improvement tests whether a policy expands opportunity and outcomes without creating new barriers.', ['advocacy', 'equity analysis', 'continuous improvement']),
    ], [['What are core MTSS literacy elements?', 'Strong core instruction, screening, follow-up, targeted support, progress monitoring, collaboration, and response-based intensity.'], ['Are tiers fixed student labels?', 'No. They describe support intensity and should change with need and response.'], ['What should program adoption examine?', 'Evidence, content, design, access, representation, fit, capacity, cost, and an evaluation plan.'], ['What limits sharing student literacy data?', 'Authorized purpose, applicable law and policy, legitimate interest, security, and minimum necessary disclosure.'], ['How should a financial conflict be handled?', 'Disclose it, preserve objective evidence and alternatives, follow rules, and recuse when necessary.'], ['What makes advocacy responsible?', 'Lived experience, disaggregated data, research, law, equity, resources, uncertainty, community voice, and evaluation.']]),
];

